#### 2.3.3 SPI Slave 测试须知[​](#233-spi-slave-测试须知 "2.3.3 SPI Slave 测试须知的直接链接")

  spi 做 slave, 要先启动 slave read, 再启动 master write, 不然会导致 slave 还没读完，master 已经写完了｡\ <!-- -->slave write,master read 也是需要先启动 slave write, 因为只有 master 送出 clk 后，slave 才会工作，同时master 会立即发送或接收数据｡

例如：在第三章节的基础上:\ <!-- -->先 slave : `echo write 0 1 16 > /dev/spi_misc_test`再 master: `echo read 0 1 16 > /dev/spi_misc_test`

### 2.4 SPI 设备驱动介绍[​](#24-spi-设备驱动介绍 "2.4 SPI 设备驱动介绍的直接链接")

  设备驱动注册:

```
#include <linux/init.h>
#include <linux/module.h>
#include <linux/platform_device.h>
#include <linux/of.h>
#include <linux/spi/spi.h>
static int spi_test_probe(struct spi_device *spi)
{
    int ret;
    if(!spi)
         return -ENOMEM;
    spi->bits_per_word= 8;
    ret= spi_setup(spi);
    if(ret < 0) {
         dev_err(&spi->dev,"ERR: fail to setup spi\n");
         return-1;
    }
    return ret;
}
static int spi_test_remove(struct spi_device *spi)
{
    printk("%s\n",__func__);
    return 0;
}
static const struct of_device_id spi_test_dt_match[]=(
    {.compatible = "rockchip,spi_test_bus1_cs0",),
    {.compatible = "rockchip,spi_test_bus1_cs1",),
    {},
);
MODULE_DEVICE_TABLE(of, spi_test_dt_match);

static struct spi_driver spi_testdriver={
    .driver={
        .name = "spi_test"
        .owner = THIS_MODULE,
        .of_match_table = of_match_ptr(spi_test_dt_match),
),
        .probe = spi_test_probe,
        .remove= spi_test_remove,
);
static int __init spi_test_init(void)
{
    int ret=0;
    ret = spi_register_driver(&spi_test_driver);
    return ret;
}
module_init (spi_test_init) ;
static void __exit spi_test_exit(void)
{
    return spi_unregister_driver(&spi_test_driver);
 }
module_exit(spi_test_exit);
```

